# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import UIKit
import SwiftUI

@main
struct PromoLinkApp: App {
    @StateObject private var promoManager = PromoManager()
    
    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(promoManager)
                .onOpenURL { url in
                    promoManager.handleUniversalLink(url)
                }
        }
    }
}

class PromoManager: ObservableObject {
    @Published var currentPromo: PromoCode?
    @Published var showPromoAlert = false
    @Published var promoMessage = ""
    
    func handleUniversalLink(_ url: URL) {
        guard url.host == "myapp.com",
              url.path == "/promo" else {
            return
        }
        
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
              let queryItems = components.queryItems else {
            return
        }
        
        var code: String?
        var discount: Int?
        
        for item in queryItems {
            switch item.name {
            case "code":
                code = item.value
            case "discount":
                if let value = item.value, let discountValue = Int(value) {
                    discount = discountValue
                }
            default:
                break
            }
        }
        
        guard let promoCode = code, let discountValue = discount else {
            promoMessage = "Invalid promo link"
            showPromoAlert = true
            return
        }
        
        applyPromoCode(code: promoCode, discount: discountValue)
    }
    
    func applyPromoCode(code: String, discount: Int) {
        let promo = PromoCode(code: code, discount: discount, appliedDate: Date())
        
        if UserAccountManager.shared.applyPromo(promo) {
            currentPromo = promo
            promoMessage = "Promo code '\(code)' applied! You got \(discount)% discount."
            showPromoAlert = true
        } else {
            promoMessage = "Failed to apply promo code. It may have already been used."
            showPromoAlert = true
        }
    }
}

struct PromoCode: Codable, Identifiable {
    let id = UUID()
    let code: String
    let discount: Int
    let appliedDate: Date
}

class UserAccountManager: ObservableObject {
    static let shared = UserAccountManager()
    
    @Published var user: UserAccount
    
    private let userDefaultsKey = "userAccount"
    
    init() {
        if let data = UserDefaults.standard.data(forKey: userDefaultsKey),
           let decoded = try? JSONDecoder().decode(UserAccount.self, from: data) {
            self.user = decoded
        } else {
            self.user = UserAccount()
        }
    }
    
    func applyPromo(_ promo: PromoCode) -> Bool {
        if user.appliedPromoCodes.contains(where: { $0.code == promo.code }) {
            return false
        }
        
        user.appliedPromoCodes.append(promo)
        user.currentDiscount = promo.discount
        saveUser()
        return true
    }
    
    func removePromo(_ promo: PromoCode) {
        user.appliedPromoCodes.removeAll { $0.code == promo.code }
        
        if let lastPromo = user.appliedPromoCodes.last {
            user.currentDiscount = lastPromo.discount
        } else {
            user.currentDiscount = 0
        }
        saveUser()
    }
    
    private func saveUser() {
        if let encoded = try? JSONEncoder().encode(user) {
            UserDefaults.standard.set(encoded, forKey: userDefaultsKey)
        }
    }
}

struct UserAccount: Codable {
    var username: String
    var email: String
    var appliedPromoCodes: [PromoCode]
    var currentDiscount: Int
    
    init(username: String = "User", email: String = "user@example.com") {
        self.username = username
        self.email = email
        self.appliedPromoCodes = []
        self.currentDiscount = 0
    }
}

